+}
+
+fn connector_rate_limits_content(uri: &str, connector_id: &str) -> mcp_resources::ResourceContent {
+    mcp_resources::ResourceContent::new(
+        uri.to_owned(),
+        json!({
+            "connector_id": connector_id,
+            "status": "unknown",
